import React from "react";
import FormTratamento from "./FormTratamento";
import OdontogramaDigital from "./OdontogramaDigital";
import ListaTratamentos from "./ListaTratamentos";
import EvolucaoTratamento from "./EvolucaoTratamento";

export default function PaginaTratamento() {
  return (
    <div className="w-full max-w-[1400px] mx-auto py-6 px-2">
      {/* TOPO: Cadastro de tratamento */}
      <div className="mb-6">
        <FormTratamento />
      </div>
      {/* GRID PRINCIPAL */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 items-start">
        {/* ESQUERDA: Lista de tratamentos */}
        <div className="bg-white rounded-xl shadow p-4 min-h-[480px]">
          <div className="font-bold mb-2">Tratamentos cadastrados</div>
          <ListaTratamentos />
        </div>
        {/* CENTRO: Odontograma */}
        <div className="bg-white rounded-xl shadow p-4 flex justify-center">
          <OdontogramaDigital />
        </div>
        {/* DIREITA: Evolução */}
        <div className="bg-white rounded-xl shadow p-4 min-h-[480px]">
          <div className="font-bold mb-2">Evolução dos tratamentos</div>
          <EvolucaoTratamento />
        </div>
      </div>
    </div>
  );
}
